import{_ as o,c as t,o as s,ah as n}from"./chunks/framework.RCw5T9E9.js";const p=JSON.parse('{"title":"JSON Mode","description":"","frontmatter":{"title":"JSON Mode"},"headers":[],"relativePath":"options/json_mode.md","filePath":"options/json_mode.md"}'),r={name:"options/json_mode.md"};function a(i,e,d,l,g,h){return s(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="json-mode" tabindex="-1">JSON Mode <a class="header-anchor" href="#json-mode" aria-label="Permalink to &quot;JSON Mode&quot;">​</a></h1><p>In <strong>Options → General</strong>, the <strong>JSON Mode</strong> switch chooses which implementation is used to <strong>view and edit JSON</strong> across the inspector (for example request/response bodies in <strong>Network</strong>, payloads in <strong>Mock response</strong>, <strong>Pinia</strong> state snapshots, and <strong>Props</strong> component data when the content is JSON).</p><p>Non-JSON bodies (XML, plain text, etc.) still use a <strong>single text view</strong> with Prism highlighting where applicable; the switch mainly affects <strong>JSON</strong> payloads.</p><hr><h2 id="classic" tabindex="-1">Classic <a class="header-anchor" href="#classic" aria-label="Permalink to &quot;Classic&quot;">​</a></h2><p><strong>Classic</strong> uses the built-in <strong>text editor with Prism syntax highlighting</strong> (<code>JsonTextEditor</code>):</p><ul><li>One <strong>plain text</strong> surface — there is <strong>no separate tree UI</strong>.</li><li><strong>Read-only</strong> views get highlighted JSON (and other supported languages).</li><li>Tuned for <strong>large fragments</strong>: above a size threshold, highlighting is reduced so the UI stays responsive (very large <strong>non-JSON</strong> read-only payloads may use a lightweight viewer instead).</li></ul><p>Choose Classic when you want a <strong>minimal, fast text-only</strong> experience.</p><hr><h2 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h2><p><strong>Advanced</strong> uses <strong>vanilla-jsoneditor</strong> (the <code>JsonEditor</code> UI component):</p><ul><li><strong>Two representations of the same JSON</strong>: <strong>Text</strong> (code) and <strong>Tree</strong> (structured). You can switch from the editor toolbar; the last choice (<strong>Text</strong> vs <strong>Tree</strong>) is <strong>remembered</strong> in settings (<code>json.mode</code>).</li><li><strong>Text mode</strong>: formatting helpers (e.g. <strong>Format</strong> / <strong>Compact</strong> where editing is allowed), <strong>Undo / Redo</strong>, <strong>Search</strong>, copy, and the same editing model as the library.</li><li><strong>Tree mode</strong>: expand/collapse, <strong>breadcrumb / path</strong> navigation, context menus on nodes, and integrated sorting / editing flows provided by the app on top of the tree.</li></ul><p>Choose Advanced when you need <strong>tree navigation</strong>, <strong>history</strong>, <strong>search</strong>, and richer editing around JSON.</p><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/options/customize.html">Customize</a> — other <strong>General</strong> options (theme, background, saved files).</li><li><a href="/qa-tools/docs/options/display_mode.html">Display modes</a> — how the inspector panel is shown on the page.</li></ul>',16)])])}const m=o(r,[["render",a]]);export{p as __pageData,m as default};
